  'DESPENSAS / ALIMENTOS Y MAS': 'Despensa y Alimentos',
  'PASTA/CAFE/CEREALES': 'Pasta, Cafe y Cereales',
  'GALLETAS/PANADERIA': 'Galletas y Panaderia',
